protected String[] flatten(Options options, String[] arguments, boolean stopAtNonOption)
{
    List<String> tokens = new ArrayList<>();

    boolean eatTheRest = false;

    for (int i = 0; i < arguments.length; i++)
    {
        String arg = arguments[i];

        if ("--".equals(arg))
        {
            eatTheRest = true;
            tokens.add("--");
        }
        else if ("-".equals(arg))
        {
            tokens.add("-");
        }
        else if (arg.startsWith("-"))
        {
            String opt = Util.stripLeadingHyphens(arg);
            int equalsIndex = arg.indexOf('=');

            if (options.hasOption(opt))
            {
                if (equalsIndex != -1)
                {
                    tokens.add(arg.substring(0, equalsIndex)); // -f
                    tokens.add(arg.substring(equalsIndex + 1)); // bar
                }
                else
                {
                    tokens.add(arg);
                }
            }
            else
            {
                if (equalsIndex != -1 && options.hasOption(arg.substring(0, equalsIndex)))
                {
                    // the format is --foo=value or -foo=value
                    // the format is a special properties option (-Dproperty=value)
                    tokens.add(arg.substring(0, equalsIndex)); // -D or --foo
                    tokens.add(arg.substring(equalsIndex + 1)); // property=value
                }
                else
                {
                    eatTheRest = stopAtNonOption;
                    tokens.add(arg);
                }
            }
        }
        else
        {
            tokens.add(arg);
        }

        if (eatTheRest)
        {
            for (i++; i < arguments.length; i++)
            {
                tokens.add(arguments[i]);
            }
        }
    }

    return tokens.toArray(new String[0]);
}

protected String[] flatten(Options options, String[] arguments, boolean stopAtNonOption)
{
    List<String> tokens = new ArrayList<>();

    boolean eatTheRest = false;

    for (int i = 0; i < arguments.length; i++)
    {
        String arg = arguments[i];

        if ("--".equals(arg))
        {
            eatTheRest = true;
            tokens.add("--");
        }
        else if ("-".equals(arg))
        {
            tokens.add("-");
        }
        else if (arg.startsWith("-"))
        {
            String opt = Util.stripLeadingHyphens(arg);

            if (options.hasOption(opt))
            {
                tokens.add(arg);
            }
            else
            {
                // Check for option=value pattern
                String[] split = arg.split("=", 2);
                if (split.length == 2 && options.hasOption(Util.stripLeadingHyphens(split[0])))
                {
                    tokens.add(split[0]);
                    tokens.add(split[1]);
                }
                else if (options.hasOption(arg.substring(0, 2)))
                {
                    // the format is --foo or -foo
                    tokens.add(arg.substring(0, 2)); // -D or --f
                    tokens.add(arg.substring(2)); // o or oo
                }
                else
                {
                    eatTheRest = stopAtNonOption;
                    tokens.add(arg);
                }
            }
        }
        else
        {
            tokens.add(arg);
        }

        if (eatTheRest)
        {
            for (i++; i < arguments.length; i++)
            {
                tokens.add(arguments[i]);
            }
        }
    }

    return tokens.toArray(new String[0]);
}

